.darma-loader-darma-custom-117 {
  width: 60px;
  aspect-ratio: 1.154;
  --c: #0000 ,var(--loader-color, #25b09b) 2deg 59deg,#0000 61deg;
  --c1:conic-gradient(from 149deg at top   ,var(--c));
  --c2:conic-gradient(from -31deg at bottom,var(--c));
  background:
    var(--c1) top,
    var(--c1) bottom right,
    var(--c2) bottom,
    var(--c1) bottom left;
  background-size: 50% 50%;
  background-repeat: no-repeat;
  animation: darma-loader-darma-custom-117-l37 1s infinite;
}
@keyframes darma-loader-darma-custom-117-l37 {
  80%,100%{background-position: bottom right,bottom left,bottom,top}
}

